import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"焰团扇","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/焰团扇.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/焰团扇.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/焰团扇.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"焰团扇",tabindex:"-1"},[s("焰团扇 "),e("a",{class:"header-anchor",href:"#焰团扇","aria-label":'Permalink to "焰团扇"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),o('<h1 id="焰团扇-1" tabindex="-1">焰团扇 <a class="header-anchor" href="#焰团扇-1" aria-label="Permalink to &quot;焰团扇&quot;">​</a></h1><p>焰团扇<br> 价格：B+2000<br> 描述：有两对六勾玉图样的葫芦形扇，把柄连有锁链，是宇智波一族代代相传的武器，外型类似日本古代将领在战场使用的军配团扇的放大版。<br> 质地坚硬而富有弹性，拥有宇智波反弹的能力，因不知其底细而死在这招下的人不计其数，曾经反弹过漩涡鸣人的小型尾兽玉。<br> 虽然名为扇，但是因为其主要功能是用于抵御攻击和施展风遁，所以这个武器其实是具有【长杆】，【双手】，【格挡10】特性的重盾，具有8L的武器伤害。只要持有这面盾牌，你就视为在防御上具有基于格挡防御的2点全能量抗力。<br> 这面扇子具有以下两种能力，一轮内，只能选择一个发动。<br> 【火遁操纵】：你可以在进行一次造成火焰伤害的攻击前，消耗一个移动动作和10点查克拉，挥动团扇，使得猛烈的狂风助长火势。这将使得这次伤害加骰等级上升一级，至多为8加骰，额外获得4点附加成功，并且出目增加一半。<br> 【宇智波反弹】：以移动动作消耗10查克拉进行一次格挡，这次格挡将具有【反震】特性。这个【反震】会基于你的格挡防御，并且造成的伤害为火焰伤害。如果对手对你的攻击未能造成伤害，那么你可以花费一个反射动作将这次【反震】所能够造成的伤害翻倍。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
